\begin{theorem}\leanok
[Pull-back of line bundles]
  \label{thm:Scheme_Pic_pullback}
  \lean{AlgebraicGeometry.Scheme.Pic.pullback}
  Let $f \colon X \to Y$ be a morphism of schemes. The categorical pull-back functor $\mathrm{Scheme.Modules.pullback}\,f \colon Y.\mathrm{Modules} \to X.\mathrm{Modules}$ induces a group homomorphism
  \[
    f^* \colon \Pic(Y) \;\to\; \Pic(X)
  \]
  by passing to invertible objects of the skeleton.
\end{theorem}

\begin{proof}
  \uses{thm:Scheme_Pic_commGroup, thm:SheafOfModules_pullback_tensorObj, thm:SheafOfModules_pullback_oneIso}
  \leanok
  The conceptual definition is $f^* = \mathrm{Units.map}(\mathrm{Skeleton.monoidHom}(\mathrm{Scheme.Modules.pullback}\,f))$, i.e.\ the units functor applied to the monoid homomorphism on skeleta induced by a monoidal functor (\texttt{Mathlib.CategoryTheory.Monoidal.Skeleton:111}). However, calling $\mathrm{Skeleton.monoidHom}$ would require a $\mathrm{Functor.Monoidal}\,(\mathrm{Scheme.Modules.pullback}\,f)$ instance, which Mathlib~\texttt{b80f227} does not register.

  The Lean construction therefore proceeds by \emph{hand-bundling} the two iso-witnesses ($\mu$-iso = Theorem~\ref{thm:SheafOfModules_pullback_tensorObj}; $\varepsilon$-iso = Theorem~\ref{thm:SheafOfModules_pullback_oneIso}) into the underlying $\mathrm{MonoidHom}\,(\mathrm{Skeleton}\,Y.\mathrm{Modules})\,(\mathrm{Skeleton}\,X.\mathrm{Modules})$ directly:
  \begin{itemize}
    \item the underlying function is $\mathrm{Functor.mapSkeleton}\,(\mathrm{Scheme.Modules.pullback}\,f)$ (Mathlib's lift of an arbitrary functor to skeleta);
    \item $\mathrm{map\_one'}$ is discharged by Theorem~\ref{thm:SheafOfModules_pullback_oneIso} (followed by the projection $\mathrm{congr\_toSkeleton\_of\_iso}$ of an iso to an equality of skeleton classes);
    \item $\mathrm{map\_mul'}$ is discharged by Theorem~\ref{thm:SheafOfModules_pullback_tensorObj} (followed by the same skeleton-of-iso projection).
  \end{itemize}
  The composite $\mathrm{Units.map}\,(\text{this MonoidHom})$ is then a group homomorphism $\Pic(Y) \to \Pic(X)$ as required. When a future Mathlib refresh lands $(\mathrm{SheafOfModules.pullback}\,f).\mathrm{Monoidal}$ the two oracle theorems collapse simultaneously into $\mathrm{MonoidalCategoryStruct.tensorObj}$-comparison and $\mathrm{Monoidal.}\varepsilon\mathrm{Iso}$, and the hand-construction may be replaced by the literal $\mathrm{Units.map} \circ \mathrm{Skeleton.monoidHom}$ form.
\end{proof}

\paragraph{Functoriality.}
The contravariant functoriality $(\mathrm{id}_X)^* = \mathrm{id}_{\Pic(X)}$ and $(g \circ f)^* = f^* \circ g^*$ is recorded by the following two lemmas; their Lean bodies are closed in iter-109 using $\mathrm{Scheme.Modules.pullbackId}$ and $\mathrm{Scheme.Modules.pullbackComp}$ respectively, plus the skeleton-of-iso projection used in $\mathrm{Pic.pullback}$.

\begin{theorem}\leanok
[Pull-back along identity]
  \label{thm:Scheme_Pic_pullback_id}
  \lean{AlgebraicGeometry.Scheme.Pic.pullback_id}
  For every scheme $X$, $\mathrm{Pic.pullback}\,(\mathrm{id}_X) = \mathrm{id}_{\Pic(X)}$.
\end{theorem}

\begin{proof}
  \uses{thm:Scheme_Pic_pullback}
  \leanok
  $\mathrm{Scheme.Modules.pullback}\,(\mathrm{id}_X)$ is naturally isomorphic to the identity functor on $X.\mathrm{Modules}$ via $\mathrm{Scheme.Modules.pullbackId}$ (existing Mathlib infrastructure); the induced monoid hom on skeleta then collapses to the identity via the skeleton-of-iso projection.
\end{proof}

\begin{theorem}\leanok
[Pull-back along composition]
  \label{thm:Scheme_Pic_pullback_comp}
  \lean{AlgebraicGeometry.Scheme.Pic.pullback_comp}
  For composable scheme morphisms $f \colon X \to Y$ and $g \colon Y \to Z$,
  $\mathrm{Pic.pullback}\,(g \circ f) = \mathrm{Pic.pullback}\,f \circ \mathrm{Pic.pullback}\,g$.
\end{theorem}

\begin{proof}
  \uses{thm:Scheme_Pic_pullback}
  \leanok
  $\mathrm{Scheme.Modules.pullback}\,(g \circ f)$ is naturally isomorphic to $\mathrm{Scheme.Modules.pullback}\,f \circ \mathrm{Scheme.Modules.pullback}\,g$ via $\mathrm{Scheme.Modules.pullbackComp}$; the same skeleton-of-iso projection transports this composition equality to the level of $\mathrm{MonoidHom}$s on skeleta.
\end{proof}

